import java.io.*;import java.util.*;class Main{static class Node{int val;ArrayList<Node>children=new ArrayList<>();Node(int v){val=v;}}static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}static TreeNode enc(Node r){if(r==null)return null;TreeNode b=new TreeNode(r.val),prev=null;for(Node c:r.children){TreeNode e=enc(c);if(prev==null)b.left=e;else prev.right=e;prev=e;}return b;}static Node dec(TreeNode r){if(r==null)return null;Node n=new Node(r.val);for(TreeNode c=r.left;c!=null;c=c.right)n.children.add(dec(c));return n;}static Node parse(String s){if(s.equals("[]"))return null;String[]tok=s.substring(1,s.length()-1).split(",");Node root=new Node(Integer.parseInt(tok[0]));ArrayDeque<Node>q=new ArrayDeque<>();q.add(root);int i=1;if(i<tok.length&&tok[i].equals("null"))i++;while(!q.isEmpty()&&i<tok.length){Node p=q.remove();while(i<tok.length&&!tok[i].equals("null")){Node c=new Node(Integer.parseInt(tok[i++]));p.children.add(c);q.add(c);}if(i<tok.length&&tok[i].equals("null"))i++;}return root;}static String fmt(Node r){if(r==null)return"[]";ArrayList<String>out=new ArrayList<>();out.add(""+r.val);out.add("null");ArrayDeque<Node>q=new ArrayDeque<>();q.add(r);while(!q.isEmpty()){Node p=q.remove();for(Node c:p.children){out.add(""+c.val);q.add(c);}out.add("null");}while(!out.isEmpty()&&out.get(out.size()-1).equals("null"))out.remove(out.size()-1);return"["+String.join(",",out)+"]";}public static void main(String[]args)throws Exception{String[]d=new String(System.in.readAllBytes()).trim().split("\\s+");if(d.length==1&&d[0].isEmpty())return;int t=Integer.parseInt(d[0]);StringBuilder out=new StringBuilder();for(int i=0;i<t;i++){if(i>0)out.append("\n\n");out.append(fmt(dec(enc(parse(d[i+1])))));}System.out.print(out);}}
